import json, re

lines = open('ios_crash.ips').readlines()
raw = ''.join(lines[1:])
raw = re.sub(r'"vmregioninfo"', '"vmregioninfo_lower"', raw)
crash = json.loads(raw)

# Check for more diagnostic info
for key in ['termination', 'asi', 'extMods', 'lastExceptionBacktrace', 'exception']:
    if key in crash:
        val = crash[key]
        print(f"=== {key} ===")
        print(json.dumps(val, indent=2)[:2000])
        print()

# Check all thread names
threads = crash.get('threads', [])
for i, t in enumerate(threads):
    name = t.get('name', '')
    triggered = t.get('triggered', False)
    queue = t.get('queue', '')
    extra = []
    if name: extra.append(f"name={name}")
    if queue: extra.append(f"queue={queue}")
    if triggered: extra.append("TRIGGERED")
    info = ", ".join(extra) if extra else "(no name)"
    print(f"Thread {i}: {info}, {len(t.get('frames',[]))} frames")

# Look for any additional fields
print("\n=== Top-level keys ===")
for k in crash.keys():
    if k not in ['threads', 'usedImages', 'lastExceptionBacktrace']:
        val = crash[k]
        if isinstance(val, (str, int, float, bool)):
            print(f"  {k}: {val}")
        elif isinstance(val, dict):
            print(f"  {k}: {json.dumps(val)[:300]}")
        elif isinstance(val, list) and len(val) < 5:
            print(f"  {k}: {json.dumps(val)[:300]}")
        else:
            print(f"  {k}: [{type(val).__name__}, len={len(val)}]")
